import{_ as e,o as a,c as r,a2 as l}from"./chunks/framework.D6hBiDio.js";const u=JSON.parse('{"title":"项目简介","description":"本项目是什么、为什么使用、开始前需要准备什么","frontmatter":{"title":"项目简介","description":"本项目是什么、为什么使用、开始前需要准备什么"},"headers":[],"relativePath":"zh/guide/introduction.md","filePath":"zh/guide/introduction.md","lastUpdated":1784575673000}'),i={name:"zh/guide/introduction.md"};function d(o,t,c,n,s,h){return a(),r("div",null,[...t[0]||(t[0]=[l('<h1 id="项目简介" tabindex="-1">项目简介 <a class="header-anchor" href="#项目简介" aria-label="Permalink to &quot;项目简介&quot;">​</a></h1><p>第一次接触本项目？从这里开始。本页说明项目用途和安装前的准备工作。</p><h2 id="本项目是什么" tabindex="-1">本项目是什么？ <a class="header-anchor" href="#本项目是什么" aria-label="Permalink to &quot;本项目是什么？&quot;">​</a></h2><p>这是一个社区维护的软件源，为 OpenWrt 设备提供<strong>更小的 Tailscale 软件包</strong>。</p><blockquote><p><a href="https://tailscale.com/" target="_blank" rel="noreferrer">Tailscale</a> 是一个零配置 VPN，能将你的设备安全地连接到一个私有网络（称为 &quot;tailnet&quot;）。它基于 WireGuard，无需端口转发即可穿透 NAT 和防火墙。</p></blockquote><p>OpenWrt 官方软件源的 Tailscale 软件包体积较大。本项目使用<strong>完全相同的 Tailscale 源码</strong>重新构建，仅做体积优化：</p><ul><li>将 <code>tailscale</code> + <code>tailscaled</code> 合并为单一二进制文件</li><li>通过编译参数裁剪可选功能（AWS、Kubernetes、Taildrop 等）</li><li>使用 <a href="https://upx.github.io/" target="_blank" rel="noreferrer">UPX</a> 压缩（<code>--best --lzma</code>）</li></ul><p><strong>效果：</strong> 二进制体积减小 30–60%，功能不变。非常适合闪存空间有限的路由器。</p><div class="tip custom-block"><p class="custom-block-title">无功能性修改</p><p>源码直接取自 <a href="https://github.com/tailscale/tailscale" target="_blank" rel="noreferrer">Tailscale 官方仓库</a>，未做任何修改。仅添加了编译参数和 UPX 压缩。 详见 <a href="/openwrt-tailscale/zh/reference/security.html">安全声明</a>。</p></div><h2 id="使用安全吗" tabindex="-1">使用安全吗？ <a class="header-anchor" href="#使用安全吗" aria-label="Permalink to &quot;使用安全吗？&quot;">​</a></h2><p>安全。整个构建过程：</p><ul><li><strong>开源化</strong> — 所有脚本和工作流均在 GitHub 公开</li><li><strong>自动化</strong> — 软件包由 GitHub Actions 构建，无人工上传</li><li><strong>可审计</strong> — 每次构建日志都公开可查</li><li><strong>可复现</strong> — 你可以按照<a href="/openwrt-tailscale/zh/build/">构建指南</a>自行构建</li></ul><p>详见 <a href="/openwrt-tailscale/zh/reference/security.html">安全声明</a>。</p><h2 id="前置要求" tabindex="-1">前置要求 <a class="header-anchor" href="#前置要求" aria-label="Permalink to &quot;前置要求&quot;">​</a></h2><p>安装前，请确认你的设备满足以下条件：</p><table tabindex="0"><thead><tr><th>要求</th><th>最低</th><th>说明</th></tr></thead><tbody><tr><td>OpenWrt 版本</td><td>22.03 或更高</td><td>可能不支持 21.02</td></tr><tr><td>存储空间</td><td>剩余 &lt; 8 MB</td><td>UPX 压缩后体积很小</td></tr><tr><td>运行内存</td><td>建议 256 MB</td><td>内存较低的设备可能需要<a href="/openwrt-tailscale/zh/guide/oom.html">内存优化</a></td></tr><tr><td>内核模块</td><td><code>kmod-tun</code>、<code>ca-bundle</code></td><td>通常已预装</td></tr><tr><td>网络</td><td>能访问 GitHub 或镜像站</td><td>用于下载软件包</td></tr></tbody></table><div class="warning custom-block"><p class="custom-block-title">低内存设备</p><p>如果你的设备运行内存低于 256 MB，Tailscale 可能被 OOM Killer 杀死。 请参考<a href="/openwrt-tailscale/zh/guide/oom.html">内存优化</a>，以更高的 CPU 占用换取更低的内存占用。</p></div><h2 id="软件包类型" tabindex="-1">软件包类型 <a class="header-anchor" href="#软件包类型" aria-label="Permalink to &quot;软件包类型&quot;">​</a></h2><p>OpenWrt 从 25.12 版本开始更换了包管理器，你需要选择正确的软件包类型：</p><table tabindex="0"><thead><tr><th>OpenWrt 版本</th><th>包管理器</th><th>软件包类型</th></tr></thead><tbody><tr><td>25.12 或更高</td><td>APK</td><td><code>.apk</code></td></tr><tr><td>24.10 或更早</td><td>OPKG</td><td><code>.ipk</code></td></tr></tbody></table><p>不知道自己的版本？<a href="/openwrt-tailscale/zh/guide/quick-start.html">快速开始</a>会教你如何查看。</p><h2 id="下一步" tabindex="-1">下一步 <a class="header-anchor" href="#下一步" aria-label="Permalink to &quot;下一步&quot;">​</a></h2><ul><li><a href="/openwrt-tailscale/zh/guide/quick-start.html">快速开始</a> — 选择安装方式</li><li><a href="/openwrt-tailscale/zh/reference/faq.html">常见问题</a> — 解答常见疑问</li><li><a href="/openwrt-tailscale/zh/reference/architectures.html">支持的架构</a> — 查看你的设备是否受支持</li></ul>',23)])])}const b=e(i,[["render",d]]);export{u as __pageData,b as default};
